CREATE MATERIALIZED VIEW IF NOT EXISTS mv_daily_account_metrics ENGINE = SummingMergeTree PARTITION BY toYYYYMM(metric_date) ORDER BY (tenant_id, subject_account_id, metric_date) AS SELECT tenant_id, subject_account_id, toDate(event_time) AS metric_date, countIf(event_type = 'comment_inbound') AS comments_inbound, countIf(event_type = 'mention_inbound') AS mentions_inbound, countIf(event_type = 'like_outbound') AS likes_outbound, countIf(event_type = 'follow_edge_added') AS follows_added, countIf(event_type = 'follow_edge_removed') AS follows_removed FROM analytics_events GROUP BY tenant_id, subject_account_id, metric_date;
